SELECT select_id, student_no, select_status, grade, select_time, course_id, course_no, course_name, course_type, credits, theory_hours, practice_hours, hours_display, semester_name, semester_code, class_time, classroom, teachers, total_hours FROM v_student_courses_detail
student_no = #{studentNo}
AND semester_code = #{semesterCode}
AND course_type = #{courseType}
AND (course_name LIKE CONCAT('%', #{keyword}, '%') OR course_no LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY semester_code DESC, course_no ASC

SELECT select_id, student_no, select_status, grade, select_time,
       course_id, course_no, course_name, course_type, credits,
       theory_hours, practice_hours, hours_display,
       semester_name, semester_code, class_time, classroom,
       teachers, total_hours
FROM v_student_courses_detail

    student_no = #{studentNo}

        AND semester_code = #{semesterCode}


        AND course_type = #{courseType}


        AND (course_name LIKE CONCAT('%', #{keyword}, '%')
             OR course_no LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY semester_code DESC, course_no ASC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM v_student_courses_detail

    student_no = #{studentNo}

        AND semester_code = #{semesterCode}


        AND course_type = #{courseType}


        AND (course_name LIKE CONCAT('%', #{keyword}, '%')
             OR course_no LIKE CONCAT('%', #{keyword}, '%'))

SELECT COUNT(*)
FROM student_courses
WHERE student_no = #{studentNo}
